const parentTaskId = $('Crear tarea principal starter').first().json.id;

const OPERACIONES = [101235303];
const CONTABILIDAD = [101235304];

const subtareas = [
  {
    nombre: "1. Confirmar recepción del brief y validar datos en Airtable",
    descripcion: "Validar la información recibida desde Tally y confirmar que los datos del cliente estén correctamente registrados en Airtable.",
    responsable: CONTABILIDAD,
    diasHabiles: 1
  },
  {
    nombre: "2. Crear carpeta del cliente en Google Drive y compartir con el equipo",
    descripcion: "Crear la estructura de carpetas del cliente y compartirla con las áreas involucradas en el proyecto.",
    responsable: OPERACIONES,
    diasHabiles: 1
  },
  {
    nombre: "3. Registrar cliente en Airtable",
    descripcion: "Crear o actualizar el registro del cliente con la información necesaria para la operación.",
    responsable: OPERACIONES,
    diasHabiles: 2
  },
  {
    nombre: "4. Notificar al equipo en Slack sobre el nuevo cliente",
    descripcion: "Informar al equipo interno sobre el ingreso del nuevo cliente y compartir la información relevante.",
    responsable: OPERACIONES,
    diasHabiles: 0
  },
  {
    nombre: "5. Agendar reunión de bienvenida (Kickoff call)",
    descripcion: "Coordinar fecha y hora para la reunión inicial de onboarding con el cliente.",
    responsable: CONTABILIDAD,
    diasHabiles: 3
  },
  {
    nombre: "6. Preparar checklist de setup básico (accesos, redes, sitio web)",
    descripcion: "Validar accesos, redes sociales, sitio web y demás recursos necesarios para iniciar la operación.",
    responsable: OPERACIONES,
    diasHabiles: 3
  }
];

function agregarDiasHabiles(fecha, dias) {
  let resultado = new Date(fecha);

  while (dias > 0) {
    resultado.setDate(resultado.getDate() + 1);

    const diaSemana = resultado.getDay();

    if (diaSemana !== 0 && diaSemana !== 6) {
      dias--;
    }
  }

  return resultado;
}

return subtareas.map(tarea => {

  const fechaVencimiento = agregarDiasHabiles(
    new Date(),
    tarea.diasHabiles
  );

  return {
    json: {
      parentTaskId,
      taskName: tarea.nombre,
      description: tarea.descripcion,
      assignee: tarea.responsable,
      dueDate: fechaVencimiento.getTime()
    }
  };
});

